import { createLinterRuleTester, LinterRuleTester } from "@typespec/compiler/testing";
import { beforeEach, describe, it } from "vitest";
import { Tester } from "../testing/test-host.js";
import { stateMachineAuthoringRule } from "./state-machine-authoring.rule.js";

describe("state-machine-authoring rule", () => {
  let ruleTester: LinterRuleTester;

  beforeEach(async () => {
    const runner = await Tester.createInstance();
    ruleTester = createLinterRuleTester(runner, stateMachineAuthoringRule, "@a10n/blueprint-typespec");
  });

  describe("valid", () => {
    // T010_01: @entity with enum field AND covering @invariant — no diagnostic
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T010.T010_01
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_state_machine_authoring:Products.A10nBlueprintEngine.Features.StateMachineAuthoring.state_via_invariants:must
    // a10n:blueprint:test Components.A10nBlueprintTypespecSdk.Operations.rule_dataset_slices_distinct:Products.A10nBlueprintEngine.Features.StateMachineAuthoring.state_via_invariants:must
    // a10n:blueprint:test-steps Components.A10nBlueprintTypespecSdk.Operations.rule_state_machine_authoring
    it("T010_01: @entity enum field with covering @invariant — no diagnostic", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            enum TaskStatus { pending, running, done }

            @entity
            model Task {
              id: string;
              status: TaskStatus;
            }
          }

          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{
              predicate: "A {@Products.MyProduct.Entities.Task.TaskStatus} value is one of pending, running, or done.",
              why: "Reason.",
            })
            op task_transition_valid(): void;
          }
        `)
        .toBeValid();
    });

    // @entity with no enum fields — no diagnostic
    it("@entity with no enum fields — no diagnostic", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            @entity
            model Task {
              id: string;
              name: string;
            }
          }
        `)
        .toBeValid();
    });

    // non-@entity model with enum field — rule skips it
    it("non-@entity model with enum field — rule skips it", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            enum SomeEnum { a, b }
            model TaskDto {
              kind: SomeEnum;
            }
          }
        `)
        .toBeValid();
    });

    // T010_05: @entity enum field covered by @invariant referencing a member ({@EnumName.value}) — no diagnostic
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T010.T010_05
    it("T010_05: @entity enum field with @invariant referencing enum member — no diagnostic", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Construct {
            enum ConstructAction { create, update, \`delete\` }

            @entity
            model Construct {
              id: string;
              action: ConstructAction;
            }
          }

          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{
              predicate: "The {@Products.MyProduct.Entities.Construct.ConstructAction.update} transition must preserve all required fields.",
              why: "Reason.",
            })
            op construct_update_valid(): void;
          }
        `)
        .toBeValid();
    });

    // @entity with enum field and @invariant using enum FQN in predicate
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T010.T010_04
    it("@entity enum field with @invariant referencing FQN — no diagnostic", async () => {
      await ruleTester
        .expect(`
          @feature
          namespace Products.MyProduct.Features.Lifecycle {
            @invariant(#{
              predicate: "A {@Products.MyProduct.Entities.Task.TaskStatus} constrains the lifecycle.",
              why: "Reason.",
            })
            op task_status_constrained(): void;
          }

          namespace Products.MyProduct.Entities.Task {
            enum TaskStatus { pending, running, done }

            @entity
            model Task {
              id: string;
              status: TaskStatus;
            }
          }
        `)
        .toBeValid();
    });
  });

  describe("invalid", () => {
    // T010_enum_no_invariant: enum field on @entity with no covering @invariant
    // a10n:blueprint Components.A10nBlueprintTypespecSdk.Tests.Rules.T010.T010_03
    it("T010_enum_no_invariant: @entity enum field without @invariant — fires noInvariant", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            enum TaskStatus { pending, running, done }

            @entity
            model Task {
              id: string;
              status: TaskStatus;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/state-machine-authoring",
          message: /TaskStatus/,
        });
    });

    // Any enum field name (not just "status") fires when uncovered
    it("enum field named 'phase' without @invariant — fires noInvariant", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Task {
            enum ReviewPhase { draft, review, approved }

            @entity
            model Review {
              id: string;
              phase: ReviewPhase;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/state-machine-authoring",
          message: /ReviewPhase/,
        });
    });

    // Enum named anything at all — must have @invariant
    it("enum field with arbitrary name without @invariant — fires noInvariant", async () => {
      await ruleTester
        .expect(`
          namespace Products.MyProduct.Entities.Order {
            enum Zustand { offen, geschlossen }

            @entity
            model Order {
              id: string;
              zustand: Zustand;
            }
          }
        `)
        .toEmitDiagnostics({
          code: "@a10n/blueprint-typespec/state-machine-authoring",
          message: /Zustand/,
        });
    });
  });
});
